Tut_lang = "AR";
Tut_date = "2026-05-09";
Tut_base = "61";

Tut_Data = {
["1"]={["Title"]="مانحو المهمات", ["Text"]="احصل على مهام عبر التحدث إلى مانحي المهام. يمتلك مانحو المهام علامات تعجب فوق رؤوسهم.|n|nللتحدث معهم، اقترب و |cffffd200نقر بزر الفأرة الأيمن|r عليهم"},
["2"]={["Title"]="الحركة", ["Text"]="استخدم مفاتيح A و S و D و W لتحريك شخصيتك."},
["3"]={["Title"]="الكاميرا", ["Text"]="يمكنك تدوير شخصيتك عن طريق |cffffd200الضغط المستمر على زر الفأرة الأيمن|r وتحريك الفأرة|n|nيمكنك النظر حولك عبر الضغط المستمر على زر الفأرة الأيسر وتحريك الفأرة."},
["4"]={["Title"]="الاستهداف", ["Text"]="|cffffd200نقر بزر الفأرة الأيمن|r على الشخصيات الودودة للتحدث معهم|n|nقد تحتاج للاقتراب منهم قبل أن تتمكن من النقر بزر الفأرة الأيمن"},
["5"]={["Title"]="وضع القتال", ["Text"]="لمقاتلة الأعداء، استخدم أولا |cffffd200نقر بزر الفأرة الأيسر|r لتحديدهم كهدف. ثم انقر على إحدى القدرات في شريط المهارات أسفل شاشتك.|n|nيجب استخدام القدرات بعيدة المدى بينما لا يزال الهدف بعيدا. تتطلب القدرات الأخرى أن تكون قريبا من هدفك، خاصة إذا كانت فئتك متخصصة في أسلحة الاشتباك."},
["6"]={["Title"]="التعويذات والقدرات", ["Text"]="الكثير من قدراتك هي هجمات سلاح أو تعويذات قتالية|n|nاعتمادا على فئتك قد تمتلك قدرات دفاعية او حتى تعويذات علاجية في شريط المهارات الخاص بك"},
["7"]={["Title"]="النهب", ["Text"]="إذا هزمت عدوا ورأيت لمعانا على جثته فهذا يعني أن لديه غنائم|n|n|cffffd200نقر بزر الفأرة الأيمن|r على جثة مخلوق لنهبها. سيؤدي هذا إلى فتح نافذة الغنائم. ثم |cffffd200نقر بزر الفأرة الأيمن|r على أي عناصر في تلك النافذة لنقلها إلى حقيبتك"},
["8"]={["Title"]="الحقيبة", ["Text"]="تمت إضافة عنصر إلى حقيبتك|n|nيمكنك النقر على |cffffd200زر الحقيبة|r في الجزء السفلي الأيمن من الشاشة لفتح الحقيبة. حرك الفأرة فوق العنصر لمعرفة ماهيته."},
["9"]={["Title"]="استخدام العناصر", ["Text"]="يمكن استخدام بعض العناصر. |cffffd200نقر بزر الفأرة الأيمن|r على عنصر لاستخدامه|n|nيمكنك سحب عنصر إلى شريط المهارات إذا كنت تريد استخدامه دون فتح الحقيبة."},
["10"]={["Title"]="الحقائب", ["Text"]="لقد حصلت على حقيبة. الآن ستتمكن من حمل المزيد من العناصر.|n|nانقل الحقيبة إلى مساحة حقيبة فارغة بجانب حقيبتك. انقر على حقيبة لفتحها."},
["11"]={["Title"]="الطعام", ["Text"]="يمكنك تناول الطعام لاستعادة الصحة بشكل اسرع |cffffd200نقر بزر الفأرة الأيمن|r على الطعام لتناوله"},
["12"]={["Title"]="الشراب", ["Text"]="يمكنك الشرب لاستعادة المانا بشكل أسرع |cffffd200نقر بزر الفأرة الأيمن|r على مشروب لتناوله|n|nلا تحتاج للشرب إذا كانت فئتك لا تستخدم المانا."},
["13"]={["Title"]="تعلم المواهب", ["Text"]="يمكنك تعلم موهبة جديدة من خلال واجهة المواهب.|n|nافتح صفحة المواهب بالنقر على |cffffd200زر المواهب النابض|r في شريط مهاراتك."},
["14"]={["Title"]="المدربون", ["Text"]="يمكنك الذهاب إلى مدرب فئتك لتعلم مهارات جديدة |cffffd200نقر بزر الفأرة الأيمن|r على المدربين للتحدث إليهم.|n|nيتواجد المدربون في العديد من البلدات أو المدن ودائما في منطقة البداية الخاصة بك. قد تضطر للبحث قليلا لتجد مدربك."},
["15"]={["Title"]="كتاب التعويذات والقدرات", ["Text"]="يمكنك نقل التعويذات والقدرات إلى شريط المهارات عبر النقر على |cffffd200زر كتاب التعويذات والقدرات|r في أسفل منتصف الشاشة ثم سحب أيقونة القدرة إلى شريط المهارات الخاص بك|n|nيمكنك ايضا استخدام تعويذة او قدرة من كتاب التعويذات مباشرة عبر النقر عليها"},
["16"]={["Title"]="السمعة", ["Text"]="يمكنك الاطلاع على سمعتك مع مجموعات مختلفة في العالم تحت تبويب السمعة.|n|nانقر على |cffffd200زر معلومات الشخصية|r للعثور على تبويب السمعة."},
["17"]={["Title"]="الرد على الرسائل الخاصة", ["Text"]="يمكنك الرد على ذلك اللاعب بالضغط على مفتاح R ثم كتابة رسالة، أو عبر الكتابة /tell <theirname> ثم الرسالة"},
["18"]={["Title"]="تشكيل مجموعة", ["Text"]="يمكنك دعوة لاعب آخر إلى مجموعتك عبر |cffffd200النقر بزر الفأرة الأيمن|r على صورته الشخصية ثم اختيار خيار |cffffd200دعوة|r من القائمة المنبثقة.|n|nيمكنك مغادرة المجموعة عبر النقر بزر الفأرة الأيمن على صورتك الشخصية واختيار خيار مغادرة المجموعة."},
["19"]={["Title"]="اللاعبون", ["Text"]="هذا شخص حقيقي آخر يلعب بشخصية. يمكنك معرفة ذلك من الاسم الأزرق فوق رأسهم."},
["20"]={["Title"]="بائعون", ["Text"]="سيؤدي |cffffd200النقر بزر الفأرة الأيمن|r على عنصر في نافذة البائع إلى شرائه إذا كان لديك مال كاف.|n|nوأثناء فتح نافذة البائع، سيؤدي النقر بزر الفأرة الأيمن على عنصر في حقيبتك إلى بيعه."},
["21"]={["Title"]="سجل المهام", ["Text"]="يمكنك عرض المهام الحالية عبر النقر على |cffffd200زر سجل المهام|r بالقرب من منتصف الجزء السفلي من شاشتك|n|nيمكنك عرض مواقع المهام بالنقر على |cffffd200زر خريطة العالم|r في أعلى يمين شاشتك"},
["22"]={["Title"]="الأصدقاء", ["Text"]="إذا كان هناك لاعب آخر استمتعت باللعب معه، أضفه إلى قائمة أصدقائك! انقر على |cffffd200زر التواصل|r وأضفهم إلى قائمة أصدقائك.|n|nيمكنك فقط إضافة أصدقاء من عالمك الخاص."},
["23"]={["Title"]="الدردشة", ["Text"]="يمكنك إرسال رسالة عبر الضغط على مفتاح إنتر، وكتابة الرسالة، ثم الضغط على إنتر مرة أخرى. سيسمع اللاعبون الآخرون القريبون منك ما تقوله."},
["24"]={["Title"]="العناصر القابلة للتجهيز", ["Text"]="يمكنك تجهيز العناصر بالنقر أولا على |cffffd200زر معلومات الشخصية|r قرب أسفل الشاشة، ثم على |cffffd200زر الحقيبة|r في أسفل يمين شاشتك.|n|nبعد ذلك اسحب أي عنصر قابل للتجهيز من حقيبتك إلى شخصيتك."},
["25"]={["Title"]="الموت", ["Text"]="أنت الآن شبح. يمكنك العودة إلى الحياة إما عن طريق العثور على جثتك أو التحدث إلى معالج أرواح قريب.|n|nتظهر جثتك كأيقونة في الخريطة المصغرة في الجزء العلوي الأيمن من الشاشة."},
["26"]={["Title"]="مستريح", ["Text"]="انت في حالة راحة. تمنحك حالة الراحة مكافأة مؤقتة للخبرة عند قتل الوحوش."},
["27"]={["Title"]="إرهاق", ["Text"]="إذا ابتعدت في مياه عميقة وغير مستكشفة، سترى شريط التعب. وإذا أصبحت متعبا تماما، ستبدأ في الغرق."},
["28"]={["Title"]="السباحة", ["Text"]="السباحة تشبه المشي كثيرا، باستثناء أنه يمكنك التوجيه للأعلى وللأسفل عبر الضغط المستمر على |cffffd200زر الفأرة الأيمن|r والنظر في الاتجاه الذي تريد الذهاب إليه"},
["29"]={["Title"]="التنفس", ["Text"]="سيظهر لك شريط النفس عندما تغمر شخصيتك في الماء. إذا نفد منك النفس، ستبدأ في الغرق."},
["30"]={["Title"]="الراحة", ["Text"]="أنت الآن في حالة راحة، ويظهر ذلك بتوهج صورتك باللون الأصفر. إن الوقت الذي تقضيه في الراحة أو أثناء تسجيل الخروج يمنحك مكافأة مؤقتة للخبرة من قتل الوحوش.|n|nيمكنك العودة بسرعة إلى النزل للراحة باستخدام حجر العودة الخاص بك."},
["31"]={["Title"]="أحجار العودة", ["Text"]="يمكن استخدام حجر الهيرثستون لنقلك من موقعك الحالي إلى الحانة التي وضعت فيها حجر الهيرثستون الخاص بك."},
["32"]={["Title"]="قتال لاعب ضد لاعب", ["Text"]="أنت الآن في قتال لاعب ضد لاعب. وأثناء مشاركتك في هذا النوع من القتال سيظهر رمز تحالفك بجوار صورتك، ويمكن للاعبين الأعداء مهاجمتك."},
["33"]={["Title"]="القفز", ["Text"]="يمكنك الضغط على |cffffd200مفتاح المسافة|r لجعل شخصيتك تقفز. يمكنك استخدام القفز لتجاوز العقبات أو لمجرد المتعة."},
["34"]={["Title"]="إكمال المهمة", ["Text"]="لقد أكملت مهمتك الأولى! للحصول على مكافأتك، عليك تسليم المهمة إلى مانح المهمة المحدد. وعادة ما يكون هذا هو نفس مانح المهمة الذي أعطاك المهمة.|n|nيمكنك رؤية مانحي المهام القريبين على هيئة |cffffd200?|r على الخريطة المصغرة في أعلى يمين الشاشة. |cffffd200انقر بزر الفأرة الأيمن|r على مانح المهمة للتحدث إليه أو إليها."},
["35"]={["Title"]="السفر", ["Text"]="هذا هو سيد الطيران الذي يدرب الوحوش الطائرة لنقل الركاب من مكان إلى آخر. مقابل رسوم بسيطة، يمكنك الانتقال بسرعة إلى أسياد طيران آخرين تحدثت إليهم سابقا.|n|nعندما تكتشف مدينة جديدة، فإن العثور على سيد الطيران سيسمح لك بالعودة بسهولة في المستقبل."},
["36"]={["Title"]="عناصر تالفة", ["Text"]="بدأت متانة أحد عناصرك تنخفض. وتشير أيقونة الشخصية أسفل الخريطة المصغرة إلى العنصر المتضرر باللون الأصفر.|n|nابحث عن بائع في المدينة لإصلاح العنصر قبل أن ينكسر."},
["37"]={["Title"]="عناصر مكسورة", ["Text"]="لقد انكسر أحد عناصرك! وتشير أيقونة الشخصية أسفل الخريطة المصغرة إلى العنصر المكسور باللون الأحمر.|n|nيمكنك إصلاح العنصر لدى بائع في المدينة. وحتى تفعل ذلك، فلن تستفيد من هذا العنصر."},
["38"]={["Title"]="المهن", ["Text"]="يمكن لشخصيتك تعلم مهن مثل الطبخ أو الحدادة، مما سيتيح لك العثور على عناصر ذات قيمة أو صنعها.|n|nلمعرفة المزيد عن المهن اسأل حارسا في مدينة رئيسية عن الاتجاهات إلى مدربي المهن"},
["39"]={["Title"]="المجموعات", ["Text"]="قد ترغب في دعوة لاعبين آخرين للتعاون معك للتغلب على أعدائك بسهولة أكبر|n|nيمكن إكمال العديد من المهام الصعبة بسرعة ضمن مجموعة، حيث يتم تقاسم رصيد المهمة بين أعضاء المجموعة. بالإضافة إلى ذلك، تحصل المجموعات على خبرة إضافية مقارنة باللاعبين المنفردين."},
["40"]={["Title"]="كتاب التعويذات", ["Text"]="لقد تعلمت تعويذة أو قدرة جديدة! استخدم |cffffd200زر كتاب التعويذات والقدرات|r قرب أسفل الشاشة لفتح كتاب التعويذات. |cffffd200انقر بزر الفأرة الأيسر واسحب|r تعويذة أو قدرة لنقلها إلى شريط المهارات.|n|nكتاب التعويذات منظم حسب الفئات، كما توضح الألسنة البارزة من الجانب الأيمن للكتاب."},
["41"]={["Title"]="مهام النخبة", ["Text"]="لقد قبلت مهمة نخبة. ومن الأفضل تنفيذ هذا النوع من المهام ضمن مجموعة، لأنها ستأخذك إلى مناطق تسكنها مخلوقات نخبة.|n|nمخلوقات النخبة أقوى بكثير من الوحوش العادية، لكنها تمنح خبرة أكثر. ويمكنك تمييز مخلوق النخبة من الإطار الذهبي على شكل تنين حول صورته."},
["42"]={["Title"]="أهلا بك في وورلد أوف ووركرافت!", ["Text"]="للبدء، عليك أن تبدأ بـ |cffffd200مهمة|r.|n|nيوجد مانح مهمة أمامك مباشرة. وستساعدك النصائح التعليمية خلال الطريق.|n|nشكرا لك على اللعب، وحظا سعيدا في مغامراتك!"},
["43"]={["Title"]="مانحو المهام غير المتاحين", ["Text"]="مانح مهمة تظهر فوق رأسه علامة '!' رمادية لديه مهمة مستواك منخفض جدا لاستلامها. عد للتحقق بمجرد اكتساب بضعة مستويات."},
["44"]={["Title"]="أسلحة بعيدة المدى", ["Text"]="لقد حصلت على سلاح بعيد المدى. ولاستخدامه، جهز السلاح أولا عبر فتح |cffffd200معلومات الشخصية|r و|cffffd200الحقيبة|r ثم سحب العنصر إلى شخصيتك.|n|nبعد ذلك افتح |cffffd200كتاب التعويذات|r واسحب قدرة |cffffd200إطلاق النار|r أو |cffffd200الرمي|r إلى شريط المهارات.|n|nلا يستطيع استخدام الأسلحة بعيدة المدى إلا الهانتر والوارير والروغ. أما الميج والبريست والوارلوك فيستطيعون استخدام العصي."},
["45"]={["Title"]="الذخيرة", ["Text"]="لا يمكنك استخدام الأقواس أو البنادق من دون ذخيرة. ولشراء الذخيرة، زر بائع الأقواس أو البنادق في المدينة. ولتجهيز الذخيرة، |cffffd200انقر بزر الفأرة الأيمن|r عليها."},
["46"]={["Title"]="مجموعات الريد", ["Text"]="لقد انضممت إلى مجموعة ريد: وهي مجموعة بحد أقصى يصل إلى 40 عضوا، رغم أنها عادة ما تكون 10 أو 25. مجموعات الريد ضرورية لدخول أصعب الدنجنز أو لهزيمة أقوى الأعداء، عادة في المستويات العالية.|n|n|cffff2020لن تحصل على تقدم في معظم المهمات أثناء وجودك في مجموعة ريد. لمغادرة مجموعة ريد، انقر بزر الفأرة الأيمن على صورة شخصيتك واختر مغادرة المجموعة.|r"},
["47"]={["Title"]="شريط التوتيم", ["Text"]="أصبح بإمكانك الآن استخدام شريط التوتيم! وستحصل على زر مهارة في هذا الشريط كلما حصلت على عنصر توتيم جديد.|n|nيمكن لهذا الشريط أن يحمل تعويذة توتيم واحدة لكل عنصر توتيم. وعند بلوغ مستويات أعلى ستكتسب القدرة على وضع عدة توتيمات دفعة واحدة."},
["48"]={["Title"]="قائمة انتظار باتل جراوند", ["Text"]="أنت الآن في قائمة انتظار لدخول باتل جراوند. يمكنك التحقق من حالتك عبر تحريك مؤشر الفأرة فوق الأيقونة على الخريطة المصغرة."},
["49"]={["Title"]="الانتقال إلى باتل جراوند", ["Text"]="لقد أصبحت مؤهلا الآن للانضمام إلى المعركة. انقر على \"دخول المعركة\" في مربع الحوار أو انقر بزر الفأرة الأيمن على أيقونة الباتل جراوند في الخريطة المصغرة."},
["50"]={["Title"]="حلقات المفاتيح", ["Text"]="لديك الآن حلقة مفاتيح لحمل مفاتيحك. ويظهر |cffffd200زر حلقة المفاتيح|r إلى يسار حقائبك في شريط المهارات."},
["51"]={["Title"]="أداة البحث عن الدنجنز", ["Text"]="يمكنك دخول الدنجنز أو العثور على مجموعات لها باستخدام |cffffd200أداة البحث عن الدنجنز|r. ويمكن الوصول إلى أداة البحث عن الدنجنز من زر العين قرب منتصف شريط المهارات."},
["52"]={["Title"]="المرافقون", ["Text"]="تهانينا، لقد حصلت على رفيقك الأول. سيتبعك هذا الرفيق الصغير خلال جميع مغامراتك في أزيروث وما بعدها.|n|nيمكنك رؤية جميع رفاقك عبر النقر على |cffffd200زر معلومات الشخصية|r ثم البحث عن تبويب الحيوانات الأليفة"},
["53"]={["Title"]="الماونتس", ["Text"]="تهانينا، لقد تعلمت كيفية استدعاء أول ماونت لك. سيحملك هذا الماونت القوي طوال مغامراتك في أزيروث وما بعدها.|n|nلرؤية جميع الماونتس، انقر على |cffffd200زر معلومات الشخصية|r ثم ابحث عن تبويب الحيوانات الأليفة. ويمكنك سحب الماونت المفضل لك إلى شريط المهارات لاستدعائه بسهولة أكبر."},
["54"]={["Title"]="تحذيرات التهديد", ["Text"]="لقد لفت انتباه مخلوق معاد لك.|n|nيعني التوهج الأحمر أن المخلوق يهاجمك. ويعني التوهج الأصفر أنك معرض للهجوم. أما التوهج البرتقالي فيعني أن المخلوق يهاجمك، لكنه قد يغير هدفه قريبا."},
["55"]={["Title"]="دينغ!", ["Text"]="تهانينا! لقد ارتفع مستواك واصبحت اكثر قوة|n|nيمكنك زيارة مدرب فئتك ومعرفة ما إذا كان لديه قدرات جديدة يمكنك تعلمها."},
["56"]={["Title"]="حالة اللاعب", ["Text"]="يوجد في الزاوية العلوية اليسرى من الشاشة شريط صحتك باللون الأخضر. وعندما يصل هذا الشريط إلى الصفر ستموت، لذا كن حذرا.|n|nأسفل شريط الصحة يوجد شريط ثان يمثل المورد الذي تستخدمه فئتك لتفعيل قدراتها الخاصة، مثل الغضب أو الطاقة أو المانا. وسيمتلئ الشريطان ببطء مع مرور الوقت."},
["57"]={["Title"]="حالة العدو", ["Text"]="تماما كما تملك شريط صحة اخضر، يملك الاعداء واحدا ايضا. عندما تختار عدوا، يمكنك رؤية شريط صحته في اعلى الشاشة وتقدير مدى قربك من هزيمته."},
["58"]={["Title"]="الحقائب ممتلئة", ["Text"]="حقائبك ممتلئة لذا لن تتمكن من التقاط المزيد من الغنائم. لتوفير مساحة في الحقيبة، قم بزيارة البائعين وبع لهم بعض الخردة.|n|nعادة ما يوجد بائعون في كل مدينة أو بلدة أو موقع."},
["59"]={["Title"]="توفير مساحة في الحقيبة", ["Text"]="لتوفير مساحة في الحقيبة أو لكسب بعض المال، يمكنك بيع بعض العناصر التي جمعتها.|n|nابحث عن بائع و|cffffd200انقر بزر الفأرة الأيمن|r عليه. ثم افتح حقائبك و|cffffd200انقر بزر الفأرة الأيمن|r على أي عناصر تريد بيعها."},
["60"]={["Title"]="القدرات الخاصة", ["Text"]="تذكر أن شخصيتك تمتلك قدرات خاصة في شريط المهارات الموجود في الجزء السفلي من شاشتك.|n|nاستخدام تلك القدرات سيقتل العدو بشكل أسرع بكثير من مجرد التلويح بسلاحك"},
["61"]={["Title"]="نسخة تجريبية", ["Text"]="هذه نسخة تجريبية من وورلد أوف ووركرافت. بعض المزايا غير متاحة."},
};
